String reverseVowels(String s) {
    StringBuilder result = new StringBuilder();
    boolean[] vowels = new boolean[26];

    for (char c : s.toCharArray()) {
        int index = (int) c - 'a';
        if (index >= 'a' && index <= 'z' && !vowels[index]) {
            result.append(c);
            vowels[index] = true;
        }
    }

    return result.reverse().toString();
}

